def write_file(relative_path: str, content: str) -> None:
    target = ROOT_DIR / relative_path
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content, encoding="utf-8")
    print(f"Yazildi: {target}")


def main() -> None:
    print("Missio ADIM 5J Python yorumlayici duzeltmesi basladi.")
    print("Security gate artik 'python' komutu yerine sys.executable kullanacak.")
    print("")

    for relative_path, content in FILES.items():
        write_file(relative_path, content)
        py_compile.compile(str(ROOT_DIR / relative_path), doraise=True)

    print("")
    print("Tamamlandi.")
    print("Simdi backend klasorunde tekrar calistir:")
    print("python -m app.commands.check_security_gate")
    print("python -m pytest tests/test_security_gate.py")


if __name__ == "__main__":
    main()
